  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// ─────────────────────────────────────────────\n// JOUEUR\n// ─────────────────────────────────────────────\nmodel Player {\n  id          String    @id @default(uuid())\n  username    String    @unique\n  email       String    @unique\n  password    String\n  villages    Village[]\n  createdAt   DateTime  @default(now())\n  totalPoints Int       @default(0)\n}\n\n// ─────────────────────────────────────────────\n// VILLAGE\n// ─────────────────────────────────────────────\nmodel Village {\n  id   String @id @default(uuid())\n  name String\n  x    Int\n  y    Int\n\n  // Ressources\n  wood  Float @default(500)\n  stone Float @default(500)\n  iron  Float @default(400)\n  food  Float @default(100)\n\n  // Niveaux de production (lecture rapide sans jointure)\n  timberCampLevel Int @default(1)\n  quarryLevel     Int @default(1)\n  ironMineLevel   Int @default(1)\n\n  // Bouclier de protection après une attaque (null = pas de bouclier actif)\n  shieldUntil DateTime?\n\n  lastTick DateTime @default(now())\n\n  // Relations\n  player   Player @relation(fields: [playerId], references: [id], onDelete: Cascade)\n  playerId String\n\n  buildings    BuildingInstance[]\n  buildQueue   BuildingQueue?\n  troops       Troop[]\n  recruitQueue RecruitQueue?\n\n  // Attaques envoyées et reçues\n  attacksSent     AttackReport[] @relation(\"AttackerVillage\")\n  attacksReceived AttackReport[] @relation(\"DefenderVillage\")\n\n  @@unique([x, y])\n}\n\n// ─────────────────────────────────────────────\n// BÂTIMENTS\n// ─────────────────────────────────────────────\nmodel BuildingInstance {\n  id         String @id @default(uuid())\n  buildingId String\n  level      Int    @default(0)\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([villageId, buildingId])\n}\n\nmodel BuildingQueue {\n  id          String @id @default(uuid())\n  buildingId  String\n  targetLevel Int\n\n  startsAt DateTime @default(now())\n  endsAt   DateTime\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String  @unique\n}\n\n// ─────────────────────────────────────────────\n// TROUPES\n// ─────────────────────────────────────────────\n\n// Stock de troupes disponibles dans un village\nmodel Troop {\n  id       String @id @default(uuid())\n  unitType String // ex: 'spearman', 'swordsman', 'axeman', 'cavalry', 'archer'\n  count    Int    @default(0)\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String\n\n  @@unique([villageId, unitType])\n}\n\n// File de recrutement (une seule file par village, comme la construction)\nmodel RecruitQueue {\n  id       String @id @default(uuid())\n  unitType String\n  count    Int // Nombre total à recruter\n  trained  Int    @default(0) // Nombre déjà recruté (pour affichage progression)\n\n  startsAt DateTime @default(now())\n  endsAt   DateTime // Fin du recrutement complet\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String  @unique\n}\n\n// ─────────────────────────────────────────────\n// COMBAT\n// ─────────────────────────────────────────────\nmodel AttackReport {\n  id String @id @default(uuid())\n\n  // Villages impliqués\n  attackerVillage   Village @relation(\"AttackerVillage\", fields: [attackerVillageId], references: [id], onDelete: Cascade)\n  attackerVillageId String\n\n  defenderVillage   Village @relation(\"DefenderVillage\", fields: [defenderVillageId], references: [id], onDelete: Cascade)\n  defenderVillageId String\n\n  // Unités envoyées { spearman: 10, cavalry: 5, ... }\n  unitsSent Json\n\n  // Unités survivantes après combat\n  unitsSurvived Json\n\n  // Unités défenseur avant/après\n  defenderUnitsBefore Json\n  defenderUnitsAfter  Json\n\n  // Ressources pillées { wood: 500, stone: 200, iron: 100 }\n  resourcesLooted Json\n\n  // Points échangés\n  pointsLost   Int @default(0) // Points perdus par le défenseur\n  pointsGained Int @default(0) // Points gagnés par l'attaquant\n\n  attackerWon Boolean\n\n  createdAt DateTime @default(now())\n}\n",
